import{c as e,S as a,j as o,m as i}from"./chunks/framework.DvQr6YbT.js";const g=JSON.parse('{"title":"分享故障排查","description":"","frontmatter":{},"headers":[],"relativePath":"zh/sharing/troubleshooting.md","filePath":"zh/sharing/troubleshooting.md","lastUpdated":1783409445000}'),r={name:"zh/sharing/troubleshooting.md"};function l(n,t,s,d,h,c){return a(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="分享故障排查" tabindex="-1">分享故障排查 <a class="header-anchor" href="#分享故障排查" aria-label="Permalink to “分享故障排查”">​</a></h1><h2 id="同事打开链接是-404-——是权限问题-不是链接坏了" tabindex="-1">&quot;同事打开链接是 404&quot;——是权限问题，不是链接坏了 <a class="header-anchor" href="#同事打开链接是-404-——是权限问题-不是链接坏了" aria-label="Permalink to “&quot;同事打开链接是 404&quot;——是权限问题，不是链接坏了”">​</a></h2><p>这是最常见的困惑，所以放在第一条：<strong>发布知识包不会授予任何人访问权。</strong>如果 知识包放在私有 GitHub 仓库里，没有读权限的人访问链接得到的就是 404——GitHub 刻意不区分&quot;不存在&quot;和&quot;无权限&quot;。</p><p>解决方式，按推荐顺序：</p><ol><li><strong>团队配置</strong>：把知识包托管在组织所有的仓库里，base permission 设为 Read—— 所有组织成员自动有权限。参见<a href="./index#团队推荐配置组织货架">组织货架</a>。</li><li><strong>个人邀请</strong>：把对方邀请为仓库 collaborator（仓库 → Settings → Collaborators），对方接受邀请后重试。</li><li>接收者下载时还必须是<em>已认证</em>状态：CLI 路径需要 <code>gh auth login</code>，手动路径 需要浏览器已登录。</li></ol><h2 id="gh-is-not-installed" tabindex="-1">&quot;gh is not installed&quot; <a class="header-anchor" href="#gh-is-not-installed" aria-label="Permalink to “&quot;gh is not installed&quot;”">​</a></h2><p><code>gh</code> 只在<strong>私有</strong>来源时需要。要么安装它（<a href="https://cli.github.com" target="_blank" rel="noreferrer">cli.github.com</a>） 并运行 <code>gh auth login</code>，要么走浏览器降级路径：从 Release 页面下载 zip，然后 <code>knowlery bundle install &lt;本地文件&gt;</code>。</p><h2 id="integrity-check-failed" tabindex="-1">&quot;Integrity check failed&quot; <a class="header-anchor" href="#integrity-check-failed" aria-label="Permalink to “&quot;Integrity check failed&quot;”">​</a></h2><p>下载的字节与 <code>--verify</code> 校验和不匹配。可能原因：分享者在公布哈希后更新了资产、 链接指向了错误的资产、或传输被篡改。请分享者重新公布当前哈希；什么都没有被安装。</p><h2 id="非-github-url-返回-download-failed-http-404" tabindex="-1">非 GitHub URL 返回 &quot;Download failed: HTTP 404&quot; <a class="header-anchor" href="#非-github-url-返回-download-failed-http-404" aria-label="Permalink to “非 GitHub URL 返回 &quot;Download failed: HTTP 404&quot;”">​</a></h2><p>该 URL 没有直接返回文件。常见于网盘类服务的&quot;分享链接&quot;——它们打开的是网页而 不是文件，你需要的是能直接返回 zip 字节流的<strong>直链</strong>。</p>',11)])])}const p=e(r,[["render",l]]);export{g as __pageData,p as default};
